import time
from functools import lru_cache

_loaded: dict = {}  # version -> model handle

def get_model(slot: str):
    version = flag_store.get(f'{slot}_model')
    if version not in _loaded:
        _loaded[version] = _load_model_weights(version)  # slow: ~30-120s
    return _loaded[version]

def warm_model(version: str) -> None:
    """Pre-load a model version into _loaded so rollback is instant."""
    if version not in _loaded:
        start = time.monotonic()
        _loaded[version] = _load_model_weights(version)
        print(f'Warmed {version} in {time.monotonic()-start:.1f}s')

def evict_old_models(keep_versions: list[str]) -> None:
    """Free GPU memory for versions no longer needed."""
    for v in list(_loaded):
        if v not in keep_versions:
            del _loaded[v]
            print(f'Evicted {v} from memory')
